#!/usr/bin/env python

from boltons.funcutils import wraps
from typing import Optional, List, Dict, Union, Callable, Any, Tuple

# Test various annotation types
print("Testing various annotation types...")

def test_decorator(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        return f(*args, **kwargs)
    return wrapper

@test_decorator
def test_optional(x: Optional[int]) -> Optional[str]:
    return str(x) if x is not None else None

@test_decorator 
def test_union(x: Union[int, str]) -> Union[int, str]:
    return x

@test_decorator
def test_list(items: List[int]) -> int:
    return sum(items)

@test_decorator
def test_dict(mapping: Dict[str, int]) -> int:
    return sum(mapping.values())

@test_decorator
def test_complex(x: Dict[str, List[Optional[int]]]) -> Optional[int]:
    for key in x:
        for item in x[key]:
            if item is not None:
                return item
    return None

@test_decorator
def test_callable(func: Callable[[int], str], value: int) -> str:
    return func(value)

@test_decorator 
def test_any(x: Any) -> Any:
    return x

@test_decorator
def test_tuple(coords: Tuple[int, int]) -> int:
    return coords[0] + coords[1]

# Run tests
print("Running tests...")

try:
    assert test_optional(42) == "42"
    assert test_optional(None) is None
    print("✓ Optional annotations work")

    assert test_union(42) == 42
    assert test_union("hello") == "hello" 
    print("✓ Union annotations work")

    assert test_list([1, 2, 3]) == 6
    print("✓ List annotations work")

    assert test_dict({"a": 1, "b": 2}) == 3
    print("✓ Dict annotations work")

    assert test_complex({"numbers": [None, 42, None]}) == 42
    print("✓ Complex nested annotations work")

    assert test_callable(str, 42) == "42"
    print("✓ Callable annotations work")

    assert test_any("anything") == "anything"
    assert test_any(123) == 123
    print("✓ Any annotations work")

    assert test_tuple((3, 4)) == 7
    print("✓ Tuple annotations work")

    print("\n🎉 All tests passed! The fix works correctly.")

except Exception as e:
    print(f"❌ Test failed: {e}")
    import traceback
    traceback.print_exc()

