from boltons.funcutils import wraps
from typing import Optional, List, Union
import sys

print("Testing edge cases...")

# Test 1: Function without annotations (should still work)
def simple_decorator(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        return f(*args, **kwargs)
    return wrapper

@simple_decorator
def no_annotations(x, y):
    return x + y

assert no_annotations(1, 2) == 3
print("✓ Functions without annotations still work")

# Test 2: Function with empty annotations dict
@simple_decorator  
def empty_annotations(x: int, y: int) -> int:
    return x + y

assert empty_annotations(1, 2) == 3
print("✓ Functions with simple annotations work")

# Test 3: Function with complex nested annotations
@simple_decorator
def complex_annotations(data: List[Optional[Union[int, str]]]) -> Optional[Union[int, str]]:
    if data:
        return data[0]
    return None

result = complex_annotations([42, "hello"])
assert result == 42
print("✓ Complex nested annotations work")

# Test 4: Function with custom type annotations (not from typing module)
class CustomType:
    pass

@simple_decorator
def custom_type_annotation(x: CustomType) -> CustomType:
    return x

custom_obj = CustomType()
assert custom_type_annotation(custom_obj) is custom_obj
print("✓ Custom type annotations work")

# Test 5: Test that typing import failure is handled gracefully
# We simulate this by temporarily removing typing from sys.modules
original_typing = sys.modules.get('typing')
if original_typing:
    sys.modules['typing'] = None  # Simulate import failure

    try:
        @simple_decorator
        def test_no_typing(x: Optional[int]) -> Optional[int]:
            return x
        # This should work because we have fallback logic
